<?php

/**
 * Prepend (or replace) the target version's section in `CHANGELOG.md`
 * with content generated by `OpenEMR\Release\ChangelogGenerator` — commits
 * walked between the previous version's tag and the current release head,
 * grouped by Conventional-Commits category and area label, filtered
 * through the same noise algorithm as the website's per-version
 * release-notes page.
 *
 * Idempotence
 *   The section for `$targetVersion` is bounded by its `## [<version>]…`
 *   heading and the next `## ` heading (or EOF). If a section already
 *   exists, this mutator replaces its content wholesale; if none exists,
 *   the new section is inserted after the `# CHANGELOG.md` header. Rerun
 *   with the same inputs → same output → no diff.
 *
 * Compare-link vs range head
 *   The compare-link URL always renders `vPREV...vNEW` for the immutable
 *   tag-to-tag diff shape. The git-range that seeds the enumerated
 *   commits uses `vNEW` when the tag already exists (finalize-partner
 *   PR, post-tag) and the rel branch tip otherwise (release-prep PR,
 *   tag not yet created). The URL renders vNEW either way; on release-
 *   prep it is aspirational — becomes valid once the tag is created
 *   during release-finalize.
 *
 * External-API dependence
 *   Unlike the pure-PHP mutators, this one shells out to `gh api` via
 *   `GitHubApi` to walk commits, resolve PRs, and fetch published GHSAs.
 *   The App token minted by release-prep.yml has the required read
 *   scopes. Release cycles are rare enough that rate limits are not a
 *   concern in practice; the alternative (offline snapshot) would
 *   diverge from live PR-label state.
 *
 * @package   OpenEMR
 * @link      http://www.open-emr.org
 * @author    Michael A. Smith <michael@opencoreemr.com>
 * @copyright Copyright (c) 2026 OpenCoreEMR Inc <https://opencoreemr.com/>
 * @license   https://github.com/openemr/openemr/blob/master/LICENSE GNU General Public License 3
 */

declare(strict_types=1);

namespace OpenEMR\Release\Mutator;

use OpenEMR\Common\Command\ReleasePrep\MutatorContext;
use OpenEMR\Common\Command\ReleasePrep\MutatorInterface;
use OpenEMR\Common\Command\ReleasePrep\MutatorResult;
use OpenEMR\Release\ChangelogGenerator;
use OpenEMR\Release\GitHubApi;
use Symfony\Component\Process\Process;

final readonly class ChangelogMutator implements MutatorInterface
{
    private const RELATIVE_PATH = 'CHANGELOG.md';
    private const REPO = 'openemr/openemr';

    public function __construct(
        private ?ChangelogGenerator $generator = null,
    ) {
    }

    public function name(): string
    {
        return 'CHANGELOG.md (prepend or replace target-version section)';
    }

    public function apply(MutatorContext $context): MutatorResult
    {
        $path = $context->projectDir . '/' . self::RELATIVE_PATH;
        $existing = file_get_contents($path);
        if ($existing === false) {
            throw new \RuntimeException('Cannot read ' . $path);
        }

        $targetVersion = $context->versionString();
        $targetTag = $context->tagName();
        $prevTag = $this->resolvePrevTag($context);
        $rangeHead = $this->resolveRangeHead($context, $targetTag);

        $generator = $this->generator ?? new ChangelogGenerator(new GitHubApi(self::REPO), self::REPO);
        $body = $generator->generate(
            base: $prevTag,
            head: $rangeHead,
            title: $targetVersion,
            includeGhsa: true,
            compareLinkOverride: $targetTag,
        );

        $updated = $this->applySection($existing, $targetVersion, $body);
        if ($updated === $existing) {
            return MutatorResult::noop();
        }

        if (file_put_contents($path, $updated) === false) {
            throw new \RuntimeException('Cannot write ' . $path);
        }

        return new MutatorResult(
            [self::RELATIVE_PATH],
            [sprintf(
                'CHANGELOG.md: %s section for %s (%s...%s range head=%s)',
                $this->sectionExists($existing, $targetVersion) ? 'refreshed' : 'prepended',
                $targetVersion,
                $prevTag,
                $targetTag,
                $rangeHead,
            )],
        );
    }

    /**
     * Highest existing `v<M>_<m>_<p>` tag whose version is strictly less
     * than the target. Sorted by git's version-aware `-v:refname`; ties
     * do not occur because tags are unique. Throws when no earlier tag
     * exists — that would indicate a fresh repository, not a real release
     * scenario, so failing loudly is preferable to guessing.
     */
    private function resolvePrevTag(MutatorContext $context): string
    {
        $process = new Process(
            ['git', 'tag', '--list', 'v[0-9]*_[0-9]*_[0-9]*', '--sort=-v:refname'],
            $context->projectDir,
        );
        $process->mustRun();

        $target = $context->versionString();
        foreach (explode("\n", trim($process->getOutput())) as $tag) {
            if ($tag === '') {
                continue;
            }
            $version = $this->versionFromTag($tag);
            if ($version === null) {
                continue;
            }
            if (version_compare($version, $target, '<')) {
                return $tag;
            }
        }

        throw new \RuntimeException(sprintf(
            'ChangelogMutator: no `v<M>_<m>_<p>` tag exists earlier than target %s in %s',
            $target,
            $context->projectDir,
        ));
    }

    /**
     * Prefer the target tag when it already exists (finalize-partner PR,
     * post-tag), fall back to the rel branch tip (release-prep PR, tag
     * not yet created). Rel branch is required in the fallback path;
     * throw when absent so the caller sees the misconfiguration instead
     * of the mutator silently reaching for HEAD.
     */
    private function resolveRangeHead(MutatorContext $context, string $targetTag): string
    {
        $process = new Process(
            ['git', 'rev-parse', '--verify', '--quiet', 'refs/tags/' . $targetTag],
            $context->projectDir,
        );
        $process->run();
        if ($process->isSuccessful()) {
            return $targetTag;
        }

        if ($context->relBranch === null) {
            throw new \RuntimeException(sprintf(
                'ChangelogMutator: target tag %s does not exist and no relBranch in context to fall back to',
                $targetTag,
            ));
        }
        return $context->relBranch;
    }

    private function versionFromTag(string $tag): ?string
    {
        if (preg_match('/^v(\d+)_(\d+)_(\d+)$/', $tag, $m) !== 1) {
            return null;
        }
        return sprintf('%d.%d.%d', (int) $m[1], (int) $m[2], (int) $m[3]);
    }

    /**
     * Insert/replace the `## [<version>]` … next-heading block. The body
     * from ChangelogGenerator ends with a newline. When prepending, we
     * add a trailing blank line to separate from the next section; when
     * replacing, the existing blank-line separator is already positioned
     * before the following heading.
     */
    private function applySection(string $existing, string $targetVersion, string $body): string
    {
        $sectionRegex = sprintf(
            '/(?ms)^## \[%s\][^\n]*\n(.*?)(?=^## |\z)/',
            preg_quote($targetVersion, '/'),
        );
        if (preg_match($sectionRegex, $existing) === 1) {
            // Replace existing section (heading + body) with the newly-rendered content.
            //
            // preg_replace_callback rather than preg_replace: $body originates
            // from live PR titles and GHSA summaries, which may contain
            // literal `$1` or `\1` sequences that preg_replace would
            // interpret as backreferences and corrupt the rewritten
            // section. The callback returns $body verbatim.
            $replacement = rtrim($body, "\n") . "\n\n";
            $replaced = preg_replace_callback(
                $sectionRegex,
                static fn (): string => $replacement,
                $existing,
                1,
            );
            if ($replaced === null) {
                throw new \RuntimeException('ChangelogMutator: preg_replace_callback failed for existing section');
            }
            return $replaced;
        }

        // Insert after the "# CHANGELOG.md" header (or at start if absent).
        $insertBefore = $this->firstEntryPosition($existing);
        return substr($existing, 0, $insertBefore)
            . rtrim($body, "\n") . "\n\n"
            . substr($existing, $insertBefore);
    }

    private function sectionExists(string $existing, string $targetVersion): bool
    {
        $pattern = sprintf('/^## \[%s\]/m', preg_quote($targetVersion, '/'));
        return preg_match($pattern, $existing) === 1;
    }

    /**
     * Byte offset of the first `## ` heading, or end-of-string when no
     * heading exists yet (very fresh file with just the top-level
     * heading). Prepending at that offset preserves the leading
     * `# CHANGELOG.md` block.
     */
    private function firstEntryPosition(string $existing): int
    {
        if (preg_match('/^## /m', $existing, $m, PREG_OFFSET_CAPTURE) === 1) {
            return $m[0][1];
        }
        return strlen($existing);
    }
}
